const StarBackground: React.FC<StarBackgroundProps> = ({ 
  density = 15, 
  className = '',
  color = 'var(--color-brand-accent)' 
}) => {
  // Generate stable positions based on density
  const stars = Array.from({ length: density }).map((_, i) => ({
    id: i,
    top: `${((i * 137) % 100)}%`, 
    left: `${((i * 243) % 100)}%`,
    scale: 0.25 + (i % 5) * 0.1, // Increased scale (approx 25px-65px)
    rotate: (i * 45) % 360,
    delay: i % 4,
  }));

  return (
    <div className={`absolute inset-0 overflow-hidden pointer-events-none z-[1] ${className}`}>
      {stars.map((star) => (
        <motion.div
          key={star.id}
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 0.28 }} // Slightly more visible
          viewport={{ once: true }}
          transition={{ duration: 1.5, delay: star.delay * 0.2 }}
          className="absolute"
          style={{
            top: star.top,
            left: star.left,
            width: '100px', 
            height: '100px',
            scale: star.scale,
            rotate: star.rotate,
          }}
        >
          <motion.div
            animate={{
              y: [0, -25, 0], // Increased floating range
              rotate: [star.rotate, star.rotate + 5, star.rotate] // Added subtle rotation float
            }}
            transition={{
              duration: 10,
              repeat: Infinity,
              ease: "easeInOut",
              delay: star.delay
            }}
            className="w-full h-full"
          >
            <BearStar color={color} />
          </motion.div>
        </motion.div>
      ))}
    </div>
  );
};

export default StarBackground;
